import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as s}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as p,X as _,Y as i,Z as e,$ as t,a1 as o,a2 as m,a0 as d,C as a}from"./framework-91490e6a.js";const u={},f=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/860386b8a8416bc9680499b2cefc8bee.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>每天在Twitter上发布日记已经是第三年了。这个专栏本身已经持续了大约两个月了。真厉害啊（自夸）。</p><p>随着时间的推移，大家可能会觉得“居然一直有话题（ネタ）啊”吧。我自己也会这样想。但是，大家生活都是满负荷的。在持续连载某个系列的时候，很少会有多余的灵感。写作者绝对会一直渴望新鲜话题。这种「渴望」可能是很重要的。</p><p>每天·每周逼近的截止日期。我甚至必须要投稿完日记后才能睡得着。但是，日常生活中很少会有像长篇故事一样有起承转合的有趣经历。那么怎么办呢？只能一味地苦苦思索。并没有什么“只要这样做的话，就能产生想法了！”之类的方法。星新一也说过。只能拼命地思考，或者看看什么东西、读读什么来逃避。</p><p>总之，只要看一部电影，写下感想，就能用作一个话题。去体验以前从未经历过的场所，那也能成为一个话题。总是不停地摆弄自己的生活，勉强地活着。边抵抗着睡意，边用乱七八糟的脑袋写下来的文章，意外地会有很多反应。总之，只要发布一些东西，就能再活一天。甚至会有一种自己是为了克服每天的截止日期而活着的错觉。然而，这种「渴望」会使人变强……不如说，那些没有截止日期却可以创作出东西的人才是异常的，为了强行留下自己的存在证明，就这样为了「文章的话题」而奉献一切啊。</p><p>当然，付出努力也有好处。通过这样的方式，我得到了写文章得到稿酬的机会；读者也会增加，因此活动的自由度也会提高。由不采取什么行动就没有东西写的恐惧推动，自然而然地变得开始看读者和看电影，积极地参加新的活动。总而言之，就像“要不要去试试针灸疗法吧！”一样。就算不行，至少也能成为一天的话题。变得「从结果来看稍微活跃」也不是什么坏事。</p><p>但是，当然也有不利之处。换句话说，当正在体验某事的时候，大脑会不停地转动，先想着将当前的情感和状况用语言表达出来的话会怎样。在感受到情绪之前，就会有一个阻挡的阶段，想着「把它写下来会怎样」。这种情况说不出是好是坏，但是总是在当前的现象之前加入一个缓冲，这有时会淡化感动。毕竟，在一个寂静的深夜的房间里，只有看动画片和电影时被感动到这种程度的乐趣。但是，在那个感动之中，会插入「啊，把这个写进文章的话可以这样写」的职业病，令人悲伤。可能漫画家们看电影时也会想「如果是我，我会用这个角度或这种台词来表达」吧。这种情况有点遗憾。</p><p>嘛，没办法。既然脑子已经变成了这样，就只能接受并继续生活下去。恐怕，即使将来发生了什么重要的事情，一瞬间也会进行「这个能写进日记吗」的判定，如果是恋爱的话，就会在那时被拒绝，如果是争吵的话，就会在那时被击倒。真是寂寞的人生。</p><hr><p><img src="'+s+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/45c6ad7499f2a3431665e399b28ab275.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【光之美少女的毛绒玩具】出现在《光之美少女》中的角色娃娃。全部都是同一个角色。不仅仅是变身前的形象，甚至连被洗脑成敌方干部时的娃娃也被商品化了，这真是罕见而令人感激。</p></blockquote>',11);function g(x,y){const n=a("ExternalLinkIcon"),r=a("RouterLink");return p(),_("div",null,[i(" more "),f,e("p",null,[t("原文链接："),e("a",h,[t("第7回／ネタに飢えた狼は眠らない"),o(n)])]),e("blockquote",null,[k,e("p",null,[o(r,{to:"/posts/Translate/nyalra_kb_06.html"},{default:m(()=>[t("【奈亚拉面壁自语】第06回｜逃离孤寂【221227】")]),_:1})])]),b])}const C=c(u,[["render",g],["__file","nyalra_kb_07.html.vue"]]);export{C as default};
